/**
 * Tests for src/lib/performance/lazy-components.ts
 *
 * Tests all pure utility functions: buildSkeletonClass, moduleLabel,
 * normaliseOptions, isHeavyModule, getCategoryDefaults, preload helpers.
 */

import {
  buildSkeletonClass,
  moduleLabel,
  normaliseOptions,
  isHeavyModule,
  getCategoryDefaults,
  preloadModule,
  isPreloaded,
  resetPreloadCache,
  HEAVY_MODULES,
  COMPONENT_CATEGORIES,
  type LazyLoadOptions,
  type ComponentCategory,
} from '@/lib/performance/lazy-components';

// ============================================================================
// buildSkeletonClass
// ============================================================================

describe('buildSkeletonClass', () => {
  it('includes base classes and height', () => {
    const cls = buildSkeletonClass(400);
    expect(cls).toContain('animate-pulse');
    expect(cls).toContain('rounded-lg');
    expect(cls).toContain('bg-muted/30');
    expect(cls).toContain('h-[400px]');
    expect(cls).toContain('w-full');
  });

  it('includes extra class when provided', () => {
    const cls = buildSkeletonClass(300, 'my-custom-class');
    expect(cls).toContain('my-custom-class');
  });

  it('does not include extra class when not provided', () => {
    const cls = buildSkeletonClass(200);
    expect(cls).not.toContain('undefined');
  });

  it('handles zero height', () => {
    const cls = buildSkeletonClass(0);
    expect(cls).toContain('h-[0px]');
  });
});

// ============================================================================
// moduleLabel
// ============================================================================

describe('moduleLabel', () => {
  it('extracts last segment of a path', () => {
    expect(moduleLabel('@/components/editor/ChatPanel')).toBe('ChatPanel');
    expect(moduleLabel('recharts')).toBe('recharts');
    expect(moduleLabel('@react-three/fiber')).toBe('fiber');
  });

  it('returns full string when no slashes', () => {
    expect(moduleLabel('lodash')).toBe('lodash');
  });

  it('handles empty string', () => {
    expect(moduleLabel('')).toBe('');
  });
});

// ============================================================================
// normaliseOptions
// ============================================================================

describe('normaliseOptions', () => {
  it('fills in all defaults when no options provided', () => {
    const opts = normaliseOptions();
    expect(opts.ssr).toBe(false);
    expect(opts.skeletonHeight).toBe(400);
    expect(opts.skeletonClassName).toBe('');
  });

  it('respects provided values', () => {
    const opts = normaliseOptions({ ssr: true, skeletonHeight: 600, skeletonClassName: 'foo' });
    expect(opts.ssr).toBe(true);
    expect(opts.skeletonHeight).toBe(600);
    expect(opts.skeletonClassName).toBe('foo');
  });

  it('fills missing fields from defaults', () => {
    const opts = normaliseOptions({ skeletonHeight: 200 });
    expect(opts.ssr).toBe(false);
    expect(opts.skeletonHeight).toBe(200);
    expect(opts.skeletonClassName).toBe('');
  });
});

// ============================================================================
// isHeavyModule
// ============================================================================

describe('isHeavyModule', () => {
  it('identifies known heavy modules', () => {
    expect(isHeavyModule('three')).toBe(true);
    expect(isHeavyModule('@react-three/fiber')).toBe(true);
    expect(isHeavyModule('react-konva')).toBe(true);
    expect(isHeavyModule('recharts')).toBe(true);
    expect(isHeavyModule('framer-motion')).toBe(true);
    expect(isHeavyModule('monaco-editor')).toBe(true);
    expect(isHeavyModule('remotion')).toBe(true);
  });

  it('identifies sub-paths of heavy modules', () => {
    expect(isHeavyModule('three/examples/jsm/loaders/GLTFLoader')).toBe(true);
    expect(isHeavyModule('recharts/es6/component/BarChart')).toBe(true);
    expect(isHeavyModule('framer-motion/dom')).toBe(true);
  });

  it('returns false for non-heavy modules', () => {
    expect(isHeavyModule('react')).toBe(false);
    expect(isHeavyModule('next/image')).toBe(false);
    expect(isHeavyModule('zod')).toBe(false);
    expect(isHeavyModule('lodash')).toBe(false);
  });

  it('is case-insensitive', () => {
    expect(isHeavyModule('Three')).toBe(true);
    expect(isHeavyModule('RECHARTS')).toBe(true);
  });

  it('trims whitespace', () => {
    expect(isHeavyModule('  three  ')).toBe(true);
  });
});

