// ============================================================================
// Preload helpers
// ============================================================================

describe('preloadModule', () => {
  beforeEach(() => {
    resetPreloadCache();
  });

  it('starts a new preload and returns true', () => {
    const loader = jest.fn().mockResolvedValue({});
    const result = preloadModule('test-module', loader);
    expect(result).toBe(true);
    expect(loader).toHaveBeenCalledTimes(1);
  });

  it('returns false on duplicate preload', () => {
    const loader = jest.fn().mockResolvedValue({});
    preloadModule('dupe', loader);
    const result = preloadModule('dupe', loader);
    expect(result).toBe(false);
    expect(loader).toHaveBeenCalledTimes(1);
  });

  it('marks module as preloaded', () => {
    preloadModule('check-me', () => Promise.resolve());
    expect(isPreloaded('check-me')).toBe(true);
    expect(isPreloaded('unknown')).toBe(false);
  });

  it('removes from cache on failure', async () => {
    const loader = jest.fn().mockRejectedValue(new Error('fail'));
    preloadModule('fail-me', loader);
    // Wait for the promise to reject
    await new Promise((r) => setTimeout(r, 10));
    expect(isPreloaded('fail-me')).toBe(false);
  });
});

describe('resetPreloadCache', () => {
  it('clears all preloaded modules', () => {
    preloadModule('a', () => Promise.resolve());
    preloadModule('b', () => Promise.resolve());
    resetPreloadCache();
    expect(isPreloaded('a')).toBe(false);
    expect(isPreloaded('b')).toBe(false);
  });
});

