describe('COMPONENT_CATEGORIES', () => {
  it('has all expected categories', () => {
    const categories: ComponentCategory[] = ['editor', 'canvas', 'chart', '3d', 'video'];
    for (const cat of categories) {
      expect(COMPONENT_CATEGORIES[cat]).toBeDefined();
      expect(COMPONENT_CATEGORIES[cat].height).toBeGreaterThan(0);
      expect(COMPONENT_CATEGORIES[cat].ssr).toBe(false);
    }
  });
});
